 1→import React from 'react';
 2→import { Screen } from '../types';
 3→import { Map, PlusCircle, BarChart2, Medal, User, TrendingUp, Download, LayoutDashboard } from 'lucide-react';
 4→
 5→type UserRole = 'agent' | 'admin' | 'client';
 6→
 7→interface Props {
 8→  currentScreen: Screen;
 9→  onNavigate: (screen: Screen) => void;
10→  isAuthenticated: boolean;
11→  isAdmin?: boolean;
12→  userRole?: UserRole;
13→  language?: 'en' | 'fr';
14→}
15→
16→const Navigation: React.FC<Props> = ({ currentScreen, onNavigate, isAuthenticated, isAdmin, userRole = 'agent', language = 'en' }) => {
17→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
18→
19→  const agentNav = [
20→    { id: Screen.HOME, label: t('Explore', 'Explorer'), icon: Map },
21→    { id: Screen.CONTRIBUTE, label: t('Contribute', 'Contribuer'), icon: PlusCircle },
22→    {
23→      id: Screen.ANALYTICS,
24→      label: isAdmin ? t('Impact', 'Impact') : t('Leaderboard', 'Classement'),
25→      icon: isAdmin ? BarChart2 : Medal
26→    },
27→    { id: isAuthenticated ? Screen.PROFILE : Screen.AUTH, label: isAuthenticated ? t('Profile', 'Profil') : t('Sign In', 'Connexion'), icon: User }
28→  ];
29→
30→  const clientNav = [
31→    { id: Screen.DELTA_DASHBOARD, label: t('Dashboard', 'Tableau'), icon: LayoutDashboard },
32→    { id: Screen.HOME, label: t('Map', 'Carte'), icon: Map },
33→    { id: Screen.ANALYTICS, label: t('Insights', 'Analyses'), icon: TrendingUp },
34→    { id: isAuthenticated ? Screen.PROFILE : Screen.AUTH, label: isAuthenticated ? t('Account', 'Compte') : t('Sign In', 'Connexion'), icon: User }
35→  ];
36→
37→  const navItems = userRole === 'client' ? clientNav : agentNav;
38→
39→  return (
40→    <nav className="min-h-16 bg-white border-t border-gray-200 flex items-center justify-around px-2 pt-1 pb-[calc(0.25rem+var(--safe-bottom))] z-40">
41→      {navItems.map((item) => {
42→        const Icon = item.icon;
43→        const isActive = currentScreen === item.id;
44→        return (
45→          <button
46→            key={item.id}
47→            onClick={() => onNavigate(item.id)}
48→            className={`flex flex-col items-center justify-center space-y-1 w-full transition-colors ${
49→              isActive ? 'text-[#0f2b46]' : 'text-gray-400 hover:text-gray-600'
50→            }`}
51→          >
52→            <Icon size={20} />
53→            <span className="text-[10px] font-medium tracking-tight uppercase">{item.label}</span>
54→          </button>
55→        );
56→      })}
57→    </nav>
58→  );
59→};
60→
61→export default Navigation;
62→

  1→import React, { Suspense, lazy, useEffect, useRef, useState } from 'react';
  2→import { Screen, DataPoint, ContributionMode } from './types';
  3→import { getSession, signOut } from './lib/client/auth';
  4→import {
  5→  flushOfflineQueue,
  6→  getQueueSnapshot,
  7→  subscribeQueueSnapshot,
  8→  type QueueItem,
  9→  type QueueSnapshot,
 10→} from './lib/client/offlineQueue';
 11→import { sendSubmissionPayload } from './lib/client/submissionSync';
 12→import type { CollectionAssignment, UserRole } from './shared/types';
 13→import Splash from './components/Screens/Splash';
 14→import Home from './components/Screens/Home';
 15→import Navigation from './components/Navigation';
 16→import ErrorBoundary from './components/ErrorBoundary';
 17→import SyncStatusBar from './components/SyncStatusBar';
 18→
 19→const Details = lazy(() => import('./components/Screens/Details'));
 20→const Auth = lazy(() => import('./components/Screens/Auth'));
 21→const ContributionFlow = lazy(() => import('./components/Screens/ContributionFlow'));
 22→const Profile = lazy(() => import('./components/Screens/Profile'));
 23→const Analytics = lazy(() => import('./components/Screens/Analytics'));
 24→const Settings = lazy(() => import('./components/Screens/Settings'));
 25→const QualityInfo = lazy(() => import('./components/Screens/QualityInfo'));
 26→const RewardsCatalog = lazy(() => import('./components/Screens/RewardsCatalog'));
 27→const AdminQueue = lazy(() => import('./components/Screens/AdminQueue'));
 28→const AgentPerformance = lazy(() => import('./components/Screens/AgentPerformance'));
 29→const DeltaDashboard = lazy(() => import('./components/Screens/DeltaDashboard'));
 30→const SubmissionQueue = lazy(() => import('./components/Screens/SubmissionQueue'));
 31→
 32→type WindowWithIdleCallback = Window & {
 33→  requestIdleCallback?: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
 34→};
 35→
 36→type ContributionLaunchOptions = {
 37→  batch?: boolean;
 38→  draft?: QueueItem | null;
 39→  point?: DataPoint | null;
 40→  assignment?: CollectionAssignment | null;
 41→};
 42→
 43→const defaultQueueSnapshot: QueueSnapshot = {
 44→  pending: 0,
 45→  failed: 0,
 46→  total: 0,
 47→  synced: 0,
 48→  queuedFailed: 0,
 49→  rejected: 0,
 50→  storageBytes: 0,
 51→};
 52→
 53→const App: React.FC = () => {
 54→  const isSyncingRef = useRef(false);
 55→  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
 56→  const [selectedPoint, setSelectedPoint] = useState<DataPoint | null>(null);
 57→  const [isOffline, setIsOffline] = useState(false);
 58→  const [isAuthenticated, setIsAuthenticated] = useState(false);
 59→  const [isAdmin, setIsAdmin] = useState(false);
 60→  const [isSyncing, setIsSyncing] = useState(false);
 61→  const [userRole, setUserRole] = useState<UserRole>('agent');
 62→  const [language, setLanguage] = useState<'en' | 'fr'>(() => {
 63→    const saved = localStorage.getItem('adl_language');
 64→    return saved === 'en' ? 'en' : 'fr';
 65→  });
 66→  const [history, setHistory] = useState<Screen[]>([]);
 67→  const [authReturnScreen, setAuthReturnScreen] = useState<Screen>(Screen.SPLASH);
 68→  const [contributionMode, setContributionMode] = useState<ContributionMode>('CREATE');
 69→  const [contributionPoint, setContributionPoint] = useState<DataPoint | null>(null);
 70→  const [contributionDraft, setContributionDraft] = useState<QueueItem | null>(null);
 71→  const [contributionAssignment, setContributionAssignment] = useState<CollectionAssignment | null>(null);
 72→  const [batchCaptureMode, setBatchCaptureMode] = useState(false);
 73→  const [queueSnapshot, setQueueSnapshot] = useState<QueueSnapshot>(defaultQueueSnapshot);
 74→
 75→  const isClient = userRole === 'client';
 76→
 77→  const navigateTo = (screen: Screen, point: DataPoint | null = null) => {
 78→    if (currentScreen === Screen.SPLASH && screen !== Screen.SPLASH) {
 79→      localStorage.setItem('adl_splash_seen', 'true');
 80→    }
 81→    if (screen === Screen.AUTH) {
 82→      setAuthReturnScreen(currentScreen);
 83→    }
 84→    setHistory((prev) => [...prev, currentScreen]);
 85→    setCurrentScreen(screen);
 86→    if (point) setSelectedPoint(point);
 87→  };
 88→
 89→  const clearContributionContext = () => {
 90→    setContributionMode('CREATE');
 91→    setContributionPoint(null);
 92→    setContributionDraft(null);
 93→    setContributionAssignment(null);
 94→    setBatchCaptureMode(false);
 95→  };
 96→
 97→  const goBack = () => {
 98→    if (history.length > 0) {
 99→      const prev = history[history.length - 1];
100→      setHistory((prevHistory) => prevHistory.slice(0, -1));
101→      setCurrentScreen(prev);
102→      return;
103→    }
104→    if (currentScreen === Screen.AUTH) {
105→      setCurrentScreen(authReturnScreen);
106→      return;
107→    }
108→    setHistory([]);
109→    setCurrentScreen(isClient ? Screen.DELTA_DASHBOARD : Screen.HOME);
110→  };
111→
112→  const switchTab = (screen: Screen) => {
113→    setHistory([]);
114→    if (screen === Screen.CONTRIBUTE && isClient) {
115→      return;
116→    }
117→    if (screen !== Screen.CONTRIBUTE) {
118→      clearContributionContext();
119→    }
120→    if (screen === Screen.CONTRIBUTE && !isAuthenticated) {
121→      setAuthReturnScreen(currentScreen);
122→      setCurrentScreen(Screen.AUTH);
123→      return;
124→    }
125→    if (screen === Screen.AUTH) {
126→      setAuthReturnScreen(currentScreen);
127→    }
128→    setCurrentScreen(screen);
129→  };
130→
131→  const openContribution = (mode: ContributionMode, options: ContributionLaunchOptions = {}) => {
132→    setContributionMode(mode);
133→    setContributionPoint(options.point ?? null);
134→    setContributionDraft(options.draft ?? null);
135→    setContributionAssignment(options.assignment ?? null);
136→    setBatchCaptureMode(Boolean(options.batch));
137→    if (isAuthenticated) {
138→      navigateTo(Screen.CONTRIBUTE);
139→      return;
140→    }
141→    navigateTo(Screen.AUTH);
142→  };
143→
144→  const runQueueSync = async () => {
145→    if (isSyncingRef.current) return;
146→    isSyncingRef.current = true;
147→    setIsSyncing(true);
148→    try {
149→      await flushOfflineQueue(sendSubmissionPayload);
150→    } catch (error) {
151→      console.error('[App] Offline queue sync failed:', error);
152→    } finally {
153→      isSyncingRef.current = false;
154→      setIsSyncing(false);
155→    }
156→  };
157→
158→  useEffect(() => {
159→    localStorage.setItem('adl_language', language);
160→    document.documentElement.lang = language;
161→  }, [language]);
162→
163→  useEffect(() => {
164→    void getQueueSnapshot().then(setQueueSnapshot).catch(() => undefined);
165→    const unsubscribe = subscribeQueueSnapshot(setQueueSnapshot);
166→    return unsubscribe;
167→  }, []);
168→
169→  useEffect(() => {
170→    const handleStatus = async () => {
171→      const online = navigator.onLine;
172→      setIsOffline(!online);
173→      if (!online) return;
174→      const windowWithIdle = window as WindowWithIdleCallback;
175→      if (typeof windowWithIdle.requestIdleCallback === 'function') {
176→        windowWithIdle.requestIdleCallback(() => {
177→          void runQueueSync();
178→        }, { timeout: 2000 });
179→        return;
180→      }
181→      window.setTimeout(() => {
182→        void runQueueSync();
183→      }, 0);
184→    };
185→
186→    window.addEventListener('online', handleStatus);
187→    window.addEventListener('offline', handleStatus);
188→    void handleStatus();
189→    return () => {
190→      window.removeEventListener('online', handleStatus);
191→      window.removeEventListener('offline', handleStatus);
192→    };
193→  }, []);
194→
195→  const refreshSession = async () => {
196→    const session = await getSession();
197→    const hasUser = !!session?.user;
198→    setIsAuthenticated(hasUser);
199→    setIsAdmin(Boolean(session?.user?.isAdmin));
200→    setUserRole((session?.user?.role as UserRole) ?? 'agent');
201→    return hasUser;
202→  };
203→
204→  useEffect(() => {
205→    const bootstrap = async () => {
206→      const hasUser = await refreshSession();
207→      const hasSeenSplash = localStorage.getItem('adl_splash_seen') === 'true';
208→      if (currentScreen === Screen.SPLASH && (hasUser || hasSeenSplash)) {
209→        setHistory([]);
210→        const session = await getSession();
211→        const role = (session?.user?.role as UserRole) ?? 'agent';
212→        setCurrentScreen(role === 'client' ? Screen.DELTA_DASHBOARD : Screen.HOME);
213→      }
214→    };
215→    void bootstrap();
216→  }, []);
217→
218→  useEffect(() => {
219→    const hasSeenSplash = localStorage.getItem('adl_splash_seen') === 'true';
220→    if (currentScreen === Screen.SPLASH && hasSeenSplash) {
221→      setHistory([]);
222→      setCurrentScreen(isClient ? Screen.DELTA_DASHBOARD : Screen.HOME);
223→    }
224→  }, [currentScreen, isClient]);
225→
226→  const renderScreen = () => {
227→    switch (currentScreen) {
228→      case Screen.SPLASH:
229→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
230→      case Screen.HOME:
231→        return (
232→          <Home
233→            onSelectPoint={(point) => navigateTo(Screen.DETAILS, point)}
234→            isAuthenticated={isAuthenticated}
235→            isAdmin={isAdmin}
236→            userRole={userRole}
237→            onAuth={() => navigateTo(Screen.AUTH)}
238→            onContribute={
239→              isClient
240→                ? undefined
241→                : (options) => openContribution('CREATE', {
242→                    batch: options?.batch,
243→                    assignment: options?.assignment ?? null,
244→                  })
245→            }
246→            onProfile={() => switchTab(Screen.PROFILE)}
247→            language={language}
248→          />
249→        );
250→      case Screen.DETAILS:
251→        return (
252→          <Details
253→            point={selectedPoint}
254→            onBack={goBack}
255→            onEnrich={() => openContribution('ENRICH', { point: selectedPoint })}
256→            onAddNew={() => openContribution('CREATE')}
257→            isAuthenticated={isAuthenticated}
258→            onAuth={() => navigateTo(Screen.AUTH)}
259→            language={language}
260→          />
261→        );
262→      case Screen.AUTH:
263→        return (
264→          <Auth
265→            language={language}
266→            onBack={goBack}
267→            onComplete={async () => {
268→              await refreshSession();
269→              const session = await getSession();
270→              const role = (session?.user?.role as UserRole) ?? 'agent';
271→              switchTab(role === 'client' ? Screen.DELTA_DASHBOARD : Screen.HOME);
272→            }}
273→          />
274→        );
275→      case Screen.CONTRIBUTE:
276→        return (
277→          <ContributionFlow
278→            language={language}
279→            onBack={goBack}
280→            onComplete={() => {
281→              clearContributionContext();
282→              switchTab(Screen.HOME);
283→            }}
284→            mode={contributionMode}
285→            seedPoint={contributionPoint}
286→            queuedDraft={contributionDraft}
287→            assignment={contributionAssignment}
288→            isBatchMode={batchCaptureMode}
289→            onQueueOpen={() => navigateTo(Screen.SUBMISSION_QUEUE)}
290→            onDraftConsumed={() => setContributionDraft(null)}
291→            onBatchExit={() => setBatchCaptureMode(false)}
292→          />
293→        );
294→      case Screen.SUBMISSION_QUEUE:
295→        return (
296→          <SubmissionQueue
297→            language={language}
298→            onBack={goBack}
299→            onEditDraft={(item) => {
300→              const mode = item.payload.eventType === 'ENRICH_EVENT' ? 'ENRICH' : 'CREATE';
301→              openContribution(mode, { draft: item });
302→            }}
303→          />
304→        );
305→      case Screen.PROFILE:
306→        return (
307→          <Profile
308→            language={language}
309→            onBack={goBack}
310→            onSettings={() => navigateTo(Screen.SETTINGS)}
311→            onRedeem={() => navigateTo(Screen.REWARDS)}
312→            onSubmissionQueue={() => navigateTo(Screen.SUBMISSION_QUEUE)}
313→          />
314→        );
315→      case Screen.ANALYTICS:
316→        return (
317→          <Analytics
318→            onBack={goBack}
319→            isAdmin={isAdmin}
320→            onAdmin={isAdmin ? () => navigateTo(Screen.ADMIN) : undefined}
321→            onAgentPerformance={isAdmin ? () => navigateTo(Screen.AGENT_PERFORMANCE) : undefined}
322→            onDeltaDashboard={isAdmin || isClient ? () => navigateTo(Screen.DELTA_DASHBOARD) : undefined}
323→            language={language}
324→          />
325→        );
326→      case Screen.SETTINGS:
327→        return (
328→          <Settings
329→            onBack={goBack}
330→            language={language}
331→            onLanguageChange={setLanguage}
332→            onLogout={async () => {
333→              try {
334→                await signOut();
335→              } catch {
336→                // Fallback to local logout even if server sign-out fails.
337→              } finally {
338→                await refreshSession();
339→                setIsAuthenticated(false);
340→                clearContributionContext();
341→                switchTab(Screen.SPLASH);
342→              }
343→            }}
344→          />
345→        );
346→      case Screen.QUALITY:
347→        return <QualityInfo language={language} onBack={goBack} />;
348→      case Screen.REWARDS:
349→        return <RewardsCatalog language={language} onBack={goBack} />;
350→      case Screen.ADMIN:
351→        return <AdminQueue language={language} onBack={goBack} />;
352→      case Screen.AGENT_PERFORMANCE:
353→        return <AgentPerformance language={language} onBack={goBack} />;
354→      case Screen.DELTA_DASHBOARD:
355→        return <DeltaDashboard language={language} onBack={goBack} />;
356→      default:
357→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
358→    }
359→  };
360→
361→  const showSyncBar = ![Screen.SPLASH, Screen.AUTH].includes(currentScreen);
362→  const showNavigation = ![Screen.SPLASH, Screen.AUTH, Screen.CONTRIBUTE].includes(currentScreen);
363→  const wideShell =
364→    currentScreen === Screen.ADMIN
365→    || currentScreen === Screen.AGENT_PERFORMANCE
366→    || (currentScreen === Screen.ANALYTICS && isAdmin)
367→    || (currentScreen === Screen.DELTA_DASHBOARD && (isAdmin || isClient));
368→
369→  return (
370→    <ErrorBoundary>
371→      <div
372→        className={`app-shell flex flex-col w-full ${wideShell ? 'max-w-7xl' : 'max-w-md'} mx-auto bg-white shadow-2xl relative overflow-hidden border-x border-gray-100 min-h-screen`}
373→      >
374→        {showSyncBar && (
375→          <SyncStatusBar
376→            pending={queueSnapshot.pending}
377→            failed={queueSnapshot.failed}
378→            synced={queueSnapshot.synced}
379→            isOffline={isOffline}
380→            isSyncing={isSyncing}
381→            onTap={() => navigateTo(Screen.SUBMISSION_QUEUE)}
382→            onRefresh={() => void runQueueSync()}
383→            language={language}
384→          />
385→        )}
386→
387→        <main className="flex-1 overflow-hidden relative">
388→          <Suspense
389→            fallback={
390→              <div className="h-full w-full bg-[#f9fafb] p-4">
391→                <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
392→                  {language === 'fr' ? 'Chargement de l ecran...' : 'Loading screen...'}
393→                </div>
394→              </div>
395→            }
396→          >
397→            {renderScreen()}
398→          </Suspense>
399→        </main>
400→
401→        {showNavigation && (
402→          <Navigation
403→            currentScreen={currentScreen}
404→            onNavigate={(screen) => switchTab(screen)}
405→            isAuthenticated={isAuthenticated}
406→            isAdmin={isAdmin}
407→            userRole={userRole}
408→            language={language}
409→          />
410→        )}
411→      </div>
412→    </ErrorBoundary>
413→  );
414→};
415→
416→export default App;
417→

