327→
328→  const filteredPoints = useMemo(() => points.filter((point) => point.type === activeCategory), [activeCategory, points]);
329→
330→  const mapPointGroups = useMemo<MapPointGroup[]>(() => {
331→    const groups = new Map<string, MapPointGroup>();
332→    for (const point of filteredPoints) {
333→      if (!point.coordinates) continue;
