 44→export async function GET(request: Request): Promise<Response> {
 45→  const auth = await requireUser(request);
 46→  if (!auth) return errorResponse("Unauthorized", 401);
 47→  const authIsAdmin = isAdminToken(auth.token);
 48→  const url = new URL(request.url);
 49→  const view = url.searchParams.get("view");
 50→
 51→  if (view === "assignments") {
 52→    const status = normalizeAssignmentStatus(url.searchParams.get("status"));
 53→    const scope = url.searchParams.get("scope");
 54→    const requestedAgent = url.searchParams.get("agentUserId")?.trim().toLowerCase() ?? null;
 55→    const allowAll = authIsAdmin && scope === "all";
 56→
 57→    try {
 58→      const assignments = await listAssignments({
 59→        viewerUserId: auth.id,
 60→        isAdmin: allowAll,
 61→        status,
 62→        agentUserId: allowAll ? requestedAgent : null,
 63→      });
 64→      return jsonResponse(assignments, { status: 200 });
 65→    } catch (error) {
 66→      if (isStorageUnavailableError(error)) {
 67→        return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
 68→      }
 69→      throw error;
 70→    }
 71→  }
 72→
 73→  if (view === "assignment_planner_context") {
 74→    if (!authIsAdmin) return errorResponse("Forbidden", 403);
 75→    const status = normalizeAssignmentStatus(url.searchParams.get("status"));
 76→    const requestedAgent = url.searchParams.get("agentUserId")?.trim().toLowerCase() ?? null;
 77→    try {
 78→      const [context, assignments] = await Promise.all([
 79→        getPlannerContext(),
 80→        listAssignments({
 81→          viewerUserId: auth.id,
 82→          isAdmin: true,
 83→          status,
 84→          agentUserId: requestedAgent,
 85→        }),
 86→      ]);
 87→      return jsonResponse({ context, assignments }, { status: 200 });
 88→    } catch (error) {
 89→      if (isStorageUnavailableError(error)) {
 90→        return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
 91→      }
 92→      throw error;
 93→    }
 94→  }
 95→
 96→  try {
 97→    const profile = await getUserProfile(auth.id);
 98→    if (!profile) return errorResponse("Profile not found", 404);
 99→
100→    if (authIsAdmin && (!profile.isAdmin || profile.mapScope !== "global")) {
101→      profile.isAdmin = true;
102→      profile.mapScope = "global";
103→      await upsertUserProfile(auth.id, profile);
104→    }
105→
106→    return jsonResponse(profile, { status: 200 });
107→  } catch (error) {
108→    if (isStorageUnavailableError(error)) {
109→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
110→    }
111→    throw error;
112→  }
113→}
