 67→async function applyReviewDecision(params: {
 68→  eventId: string;
 69→  reviewerId: string;
 70→  decision: ReviewDecision;
 71→  notes: string | null;
 72→}): Promise<{ eventId: string; decision: ReviewDecision; reviewStatus: string; xpAwarded: number; userId: string }> {
 73→  const result = await query<{ user_id: string; details: Record<string, unknown> }>(
 74→    `SELECT user_id, details
 75→     FROM point_events
 76→     WHERE id = $1::uuid
 77→     LIMIT 1`,
 78→    [params.eventId],
 79→  );
 80→  const row = result.rows[0];
 81→  if (!row) {
 82→    throw new Error("Submission event not found");
 83→  }
 84→
 85→  const details = row.details && typeof row.details === "object" ? ({ ...row.details } as Record<string, unknown>) : {};
 86→  const currentXpAwarded = typeof details.xpAwarded === "number" && Number.isFinite(details.xpAwarded) ? details.xpAwarded : 0;
 87→  const shouldGrantXp = params.decision === "approved" && currentXpAwarded <= 0;
 88→  const nextXpAwarded = shouldGrantXp ? BASE_EVENT_XP : currentXpAwarded;
 89→  const reviewStatus = params.decision === "approved" ? "auto_approved" : "pending_review";
 90→
 91→  details.reviewStatus = reviewStatus;
 92→  details.reviewDecision = params.decision;
 93→  details.reviewedBy = params.reviewerId;
 94→  details.reviewedAt = new Date().toISOString();
 95→  if (params.notes) details.reviewNotes = params.notes;
 96→  if (nextXpAwarded > 0) details.xpAwarded = nextXpAwarded;
 97→
 98→  if (params.decision === "rejected") {
 99→    const existingFlags = Array.isArray(details.reviewFlags) ? details.reviewFlags.filter((f) => typeof f === "string") : [];
100→    if (!existingFlags.includes("rejected_by_admin")) existingFlags.push("rejected_by_admin");
101→    details.reviewFlags = existingFlags;
102→  }
103→
104→  await query(
105→    `UPDATE point_events
106→     SET details = $2::jsonb
107→     WHERE id = $1::uuid`,
108→    [params.eventId, JSON.stringify(details)],
109→  );
110→
111→  try {
112→    await query(
113→      `INSERT INTO admin_reviews (event_id, reviewer_id, decision, notes)
114→       VALUES ($1::uuid, $2, $3, $4)
115→       ON CONFLICT (event_id) DO UPDATE SET
116→         reviewer_id = EXCLUDED.reviewer_id,
117→         decision = EXCLUDED.decision,
118→         notes = EXCLUDED.notes,
119→         reviewed_at = NOW()`,
120→      [params.eventId, params.reviewerId, params.decision, params.notes],
121→    );
122→  } catch (error) {
123→    if (!isMissingDbObjectError(error)) throw error;
124→  }
125→
126→  if (shouldGrantXp) {
127→    const profile = await getUserProfile(row.user_id);
128→    if (profile) {
129→      profile.XP = (profile.XP ?? 0) + BASE_EVENT_XP;
130→      await upsertUserProfile(row.user_id, profile);
131→    }
132→  }
133→
134→  return {
135→    eventId: params.eventId,
136→    decision: params.decision,
137→    reviewStatus,
138→    xpAwarded: nextXpAwarded,
139→    userId: row.user_id,
140→  };
141→}
