  1→import { Auth } from "@auth/core";
  2→import Credentials from "@auth/core/providers/credentials";
  3→import Google from "@auth/core/providers/google";
  4→import type { AppProviders } from "@auth/core/providers";
  5→import bcrypt from "bcryptjs";
  6→import type { UserProfile } from "../../../shared/types.js";
  7→import { errorResponse } from "../http.js";
  8→import { getUserProfile, isStorageUnavailableError, upsertUserProfile } from "../storage/index.js";
  9→import { getAuthSecret, getSessionCookieName, isSecureRequest } from "../../auth.js";
 10→import { inferDefaultDisplayName, normalizeEmail, normalizeIdentifier } from "../../shared/identifier.js";
 11→import { withAbsoluteUrl } from "./requestUrl.js";
 12→
 13→const googleClientId = process.env.GOOGLE_CLIENT_ID ?? "";
 14→const googleClientSecret = process.env.GOOGLE_CLIENT_SECRET ?? "";
 15→
 16→const providers: AppProviders = [
 17→  Credentials({
 18→    name: "Credentials",
 19→    credentials: {
 20→      identifier: { label: "Phone or email", type: "text" },
 21→      email: { label: "Email", type: "text" },
 22→      password: { label: "Password", type: "password" },
 23→    },
 24→    async authorize(credentials) {
 25→      const rawIdentifier =
 26→        typeof credentials?.identifier === "string"
 27→          ? credentials.identifier
 28→          : typeof credentials?.email === "string"
 29→            ? credentials.email
 30→            : "";
 31→      const normalizedIdentifier = normalizeIdentifier(rawIdentifier);
 32→      const password = typeof credentials?.password === "string" ? credentials.password : "";
 33→
 34→      if (!normalizedIdentifier || !password) return null;
 35→      const identifier = normalizedIdentifier.value;
 36→
 37→      const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
 38→      const adminPassword = process.env.ADMIN_PASSWORD ?? "";
 39→      if (adminEmail && adminPassword && normalizedIdentifier.type === "email" && identifier === adminEmail) {
 40→        let adminMatch = false;
 41→        if (adminPassword.startsWith("$2")) {
 42→          adminMatch = await bcrypt.compare(password, adminPassword);
 43→        } else {
 44→          // Fallback for plain-text password (legacy). Update ADMIN_PASSWORD to a bcrypt hash.
 45→          console.warn("[auth] ADMIN_PASSWORD is not a bcrypt hash. Please update it to a bcrypt hash.");
 46→          adminMatch = password === adminPassword;
 47→        }
 48→        if (adminMatch) return { id: identifier, name: "Admin", email: identifier };
 49→      }
 50→
 51→      const profile = await getUserProfile(identifier);
 52→      if (!profile?.passwordHash) return null;
 53→
 54→      const valid = bcrypt.compareSync(password, profile.passwordHash);
 55→      if (!valid) return null;
 56→
 57→      const fallbackName = inferDefaultDisplayName(profile.email ?? profile.phone ?? profile.id);
 58→      return { id: profile.id, name: profile.name || fallbackName, email: profile.email ?? undefined };
 59→    },
 60→  }),
 61→];
 62→
 63→if (googleClientId && googleClientSecret) {
 64→  providers.unshift(
 65→    Google({
 66→      clientId: googleClientId,
 67→      clientSecret: googleClientSecret,
 68→      token: {
 69→        async conform(response) {
 70→          // Auth.js v0.33 throws "TODO: Handle OIDC response body error" when
 71→          // the token response content-type isn't exactly "application/json".
 72→          // Google sometimes returns "application/json; charset=utf-8" which
 73→          // triggers this bug. Fix by re-wrapping with a clean content-type.
 74→          if (!response.ok) {
 75→            const body = await response.text().catch(() => "");
 76→            const trimmed = body.length > 1200 ? `${body.slice(0, 1200)}…` : body;
 77→            console.error("[auth] google token endpoint response error", {
 78→              status: response.status,
 79→              statusText: response.statusText,
