import React, { Suspense, useEffect, useMemo, useRef, useState } from 'react';
import { Category, DataPoint } from '../../types';
import type { CollectionAssignment, MapScope, PointEvent, ProjectedPoint, UserRole } from '../../shared/types';
import {
  BONAMOUSSADI_CENTER,
  CAMEROON_CENTER,
  bonamoussadiLeafletBounds,
  cameroonLeafletBounds,
  isWithinBonamoussadi
} from '../../shared/geofence';
import {
  ChevronDown,
  List,
  Map as MapIcon,
  MapPin,
  Plus,
  ShieldCheck,
  User
} from 'lucide-react';
import VerticalIcon from '../shared/VerticalIcon';
import { categoryLabel as getCategoryLabel, LEGACY_CATEGORY_MAP, VERTICALS } from '../../shared/verticals';
import { apiJson } from '../../lib/client/api';
import { detectLowEndDevice } from '../../lib/client/deviceProfile';
import { getSession } from '../../lib/client/auth';
import BrandLogo from '../BrandLogo';
import DailyProgressWidget from '../DailyProgressWidget';
import StreakTracker from '../StreakTracker';

interface Props {
  onSelectPoint: (point: DataPoint) => void;
  isAuthenticated: boolean;
  isAdmin?: boolean;
  userRole?: UserRole;
  onAuth: () => void;
  onContribute?: (options?: { batch?: boolean; assignment?: CollectionAssignment | null }) => void;
  onProfile: () => void;
  language: 'en' | 'fr';
}

type MapPointGroup = {
  key: string;
  latitude: number;
  longitude: number;
  points: DataPoint[];
};

const HomeMap = React.lazy(() => import('./HomeMap'));

const BONAMOUSSADI_MAP_BOUNDS = bonamoussadiLeafletBounds();
const CAMEROON_MAP_BOUNDS = cameroonLeafletBounds();

const normalizeMapScope = (scope: unknown, isAdminMode: boolean): MapScope => {
  if (isAdminMode) return 'global';
  if (scope === 'cameroon' || scope === 'global') return scope;
  return 'bonamoussadi';
};

const categoryFromSubmission = (category: ProjectedPoint['category']): Category => {
  if (category === 'pharmacy') return Category.PHARMACY;
  if (category === 'fuel_station') return Category.FUEL;
  if (category === 'mobile_money') return Category.MOBILE_MONEY;
  if (category === 'alcohol_outlet') return Category.ALCOHOL_OUTLET;
  if (category === 'billboard') return Category.BILLBOARD;
  if (category === 'transport_road') return Category.TRANSPORT_ROAD;
  if (category === 'census_proxy') return Category.CENSUS_PROXY;
  return Category.PHARMACY;
};

const selectableCategories: Category[] = [
  Category.PHARMACY,
  Category.FUEL,
  Category.MOBILE_MONEY,
  Category.ALCOHOL_OUTLET,
  Category.BILLBOARD,
  Category.TRANSPORT_ROAD,
  Category.CENSUS_PROXY,
];


const Home: React.FC<Props> = ({ onSelectPoint, isAuthenticated, isAdmin, userRole = 'agent', onAuth, onContribute, onProfile, language }) => {
  const [deviceRuntime] = useState(() => ({ lowEnd: detectLowEndDevice() }));
  const [viewMode, setViewMode] = useState<'map' | 'list'>(() => (deviceRuntime.lowEnd ? 'list' : 'map'));
  const [activeCategory, setActiveCategory] = useState<Category>(Category.PHARMACY);
  const [isVerticalPickerOpen, setIsVerticalPickerOpen] = useState(false);
  const [points, setPoints] = useState<DataPoint[]>([]);
  const [isLoadingPoints, setIsLoadingPoints] = useState(true);
  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
  const [agentEvents, setAgentEvents] = useState<PointEvent[]>([]);
  const [mapScope, setMapScope] = useState<MapScope>(() => (isAdmin ? 'global' : 'bonamoussadi'));
  const contributePressTimer = useRef<number | null>(null);
  const longPressTriggered = useRef(false);
  const isLowEndDevice = deviceRuntime.lowEnd;
  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);

  const selectedCityLabel =
    mapScope === 'cameroon'
      ? t('Cameroon', 'Cameroun')
      : mapScope === 'global'
        ? t('Worldwide', 'Monde entier')
        : t('Bonamoussadi, Douala, Cameroon', 'Bonamoussadi, Douala, Cameroun');

  const mapCenter: [number, number] =
    mapScope === 'cameroon'
      ? [CAMEROON_CENTER.latitude, CAMEROON_CENTER.longitude]
      : mapScope === 'global'
        ? [20, 0]
        : [BONAMOUSSADI_CENTER.latitude, BONAMOUSSADI_CENTER.longitude];
  const mapZoom = mapScope === 'cameroon' ? 6 : mapScope === 'global' ? 2 : 15;
  const mapMinZoom = mapScope === 'cameroon' ? 5 : mapScope === 'global' ? 2 : 14;
  const mapBounds =
    mapScope === 'bonamoussadi' ? BONAMOUSSADI_MAP_BOUNDS : mapScope === 'cameroon' ? CAMEROON_MAP_BOUNDS : undefined;
  const mapLockLabel =
    mapScope === 'bonamoussadi'
      ? t('GPS Locked', 'GPS verrouille')
      : t('GPS Unlocked (Admin)', 'GPS debloque (admin)');

  const formatTimeAgo = (iso: string) => {
    const created = new Date(iso).getTime();
    if (Number.isNaN(created)) return t('Unknown', 'Inconnu');
    const diffMs = Date.now() - created;
    const minutes = Math.max(1, Math.round(diffMs / 60000));
    if (minutes < 60) return language === 'fr' ? `il y a ${minutes} min` : `${minutes} mins ago`;
    const hours = Math.round(minutes / 60);
    if (hours < 24) return language === 'fr' ? `il y a ${hours}h` : `${hours}h ago`;
    const days = Math.round(hours / 24);
    return language === 'fr' ? `il y a ${days}j` : `${days}d ago`;
  };

  const inferAvailability = (category: ProjectedPoint['category'], details: Record<string, unknown>): 'High' | 'Low' | 'Out' => {
    if (category === 'pharmacy') {
      if (typeof details.isOpenNow === 'boolean') return details.isOpenNow ? 'High' : 'Out';
      return 'Low';
    }
    if (category === 'fuel_station') {
      if (typeof details.hasFuelAvailable === 'boolean') return details.hasFuelAvailable ? 'High' : 'Out';
      return 'Low';
    }
    const hasMin50000XafAvailable =
      typeof details.hasMin50000XafAvailable === 'boolean'
        ? details.hasMin50000XafAvailable
        : typeof details.hasCashAvailable === 'boolean'
          ? details.hasCashAvailable
          : undefined;
    if (typeof hasMin50000XafAvailable === 'boolean') return hasMin50000XafAvailable ? 'High' : 'Out';
    return 'Low';
  };

  const mapProjectedToPoint = (point: ProjectedPoint): DataPoint => {
    const details = (point.details ?? {}) as Record<string, unknown>;
    const type = categoryFromSubmission(point.category);
    const name =
      (typeof details.name === 'string' && details.name) ||
      (typeof details.siteName === 'string' && details.siteName) ||
      getCategoryLabel(point.category, language);
    const pricesByFuel =
      details.pricesByFuel && typeof details.pricesByFuel === 'object'
        ? (details.pricesByFuel as Record<string, number>)
        : undefined;
    const derivedPrice =
      typeof details.fuelPrice === 'number'
        ? details.fuelPrice
        : typeof details.price === 'number'
          ? details.price
          : pricesByFuel
            ? Object.values(pricesByFuel).find((value) => Number.isFinite(value))
            : undefined;
    const providers = Array.isArray(details.providers)
      ? (details.providers as string[]).filter((value) => typeof value === 'string' && value.trim().length > 0)
      : [];
    const paymentMethods = Array.isArray(details.paymentMethods)
      ? (details.paymentMethods as string[])
      : Array.isArray(details.paymentModes)
        ? (details.paymentModes as string[])
        : undefined;
    const provider = typeof details.provider === 'string' && details.provider.trim() ? details.provider.trim() : providers[0];
    const operator =
      (typeof details.operator === 'string' && details.operator.trim()) ||
      provider ||
      (providers.length > 0 ? providers[0] : undefined);

    return {
      id: point.pointId,
      name,
      type,
      location: `GPS: ${point.location.latitude.toFixed(4)}°, ${point.location.longitude.toFixed(4)}°`,
      coordinates: { latitude: point.location.latitude, longitude: point.location.longitude },
      price: typeof derivedPrice === 'number' ? derivedPrice : undefined,
      fuelType:
        (typeof details.fuelType === 'string' && details.fuelType) ||
        (Array.isArray(details.fuelTypes) ? String(details.fuelTypes[0] ?? '') : undefined),
      fuelTypes: Array.isArray(details.fuelTypes) ? (details.fuelTypes as string[]) : undefined,
      pricesByFuel: pricesByFuel,
      quality: typeof details.quality === 'string' ? details.quality : undefined,
      currency: 'XAF',
      lastUpdated: formatTimeAgo(point.updatedAt),
      availability: inferAvailability(point.category, details),
      queueLength: typeof details.queueLength === 'string' ? details.queueLength : undefined,
      trustScore: 85,
      contributorTrust: 'Silver',
      provider,
      providers,
      operator,
      merchantId: typeof details.merchantId === 'string' ? details.merchantId : undefined,
      hasMin50000XafAvailable:
        typeof details.hasMin50000XafAvailable === 'boolean'
          ? details.hasMin50000XafAvailable
          : typeof details.hasCashAvailable === 'boolean'
            ? details.hasCashAvailable
            : undefined,
      hasCashAvailable:
        typeof details.hasCashAvailable === 'boolean'
          ? details.hasCashAvailable
          : typeof details.hasMin50000XafAvailable === 'boolean'
            ? details.hasMin50000XafAvailable
            : undefined,
      hasFuelAvailable: typeof details.hasFuelAvailable === 'boolean' ? details.hasFuelAvailable : undefined,
      openingHours: typeof details.openingHours === 'string' ? details.openingHours : undefined,
      isOpenNow: typeof details.isOpenNow === 'boolean' ? details.isOpenNow : undefined,
      isOnDuty: typeof details.isOnDuty === 'boolean' ? details.isOnDuty : undefined,
      paymentMethods: paymentMethods?.filter((value) => typeof value === 'string' && value.trim().length > 0),
      reliability: typeof details.reliability === 'string' ? details.reliability : undefined,
      photoUrl: typeof point.photoUrl === 'string' ? point.photoUrl : undefined,
      gaps: Array.isArray(point.gaps) ? point.gaps : [],
      verified: true
    };
  };

  const formatPaymentMethods = (paymentMethods: string[] | undefined) => {
    if (!paymentMethods || paymentMethods.length === 0) {
      return t('Accepted payments unavailable', 'Paiements acceptes indisponibles');
    }
    return paymentMethods.join(', ');
  };

  const formatExplorerPrimaryMeta = (point: DataPoint) => {
    if (point.type === Category.PHARMACY) {
      if (typeof point.isOnDuty === 'boolean') {
        return point.isOnDuty ? t('Pharmacie de garde', 'Pharmacie de garde') : t('Pas de garde', 'Pas de garde');
      }
      return t('Statut de garde indisponible', 'Statut de garde indisponible');
    }
    if (point.type === Category.FUEL) {
      return `${t('Paiements', 'Paiements')}: ${formatPaymentMethods(point.paymentMethods)}`;
    }
    const operator = point.operator || point.provider || point.providers?.[0];
    return operator ? `${t('Operateur', 'Operateur')}: ${operator}` : t('Operateur indisponible', 'Operateur indisponible');
  };

  const formatPharmacyOpenStatus = (point: DataPoint) => {
    if (point.type !== Category.PHARMACY) return null;
    return point.isOpenNow ? t('Ouvert maintenant', 'Ouvert maintenant') : t('Statut indisponible', 'Statut indisponible');
  };

  useEffect(() => {
    if (!isAuthenticated || !isAdmin) {
      setMapScope('bonamoussadi');
      return;
    }
    setMapScope('global');
  }, [isAuthenticated, isAdmin]);

  useEffect(() => {
    const loadPoints = async () => {
      try {
        setIsLoadingPoints(true);
        const params = new URLSearchParams();
        if (mapScope !== 'bonamoussadi') params.set('scope', mapScope);
        const query = params.toString();
        const data = await apiJson<ProjectedPoint[]>(query ? `/api/submissions?${query}` : '/api/submissions');
        if (Array.isArray(data)) {
          const mapped = data
            .map(mapProjectedToPoint)
            .filter((point) => (mapScope === 'bonamoussadi' ? isWithinBonamoussadi(point.coordinates) : true));
          setPoints(mapped);
        }
      } catch {
        setPoints([]);
      } finally {
        setIsLoadingPoints(false);
      }
    };
    void loadPoints();
  }, [language, mapScope]);

  useEffect(() => {
    let cancelled = false;
    const loadAgentData = async () => {
      if (!isAuthenticated || userRole === 'client') {
        setAssignments([]);
        setAgentEvents([]);
        return;
      }

      try {
        const eventsParams = new URLSearchParams({ view: 'events' });
        if (isAdmin) eventsParams.set('scope', 'global');
        const [session, assignmentData, eventData] = await Promise.all([
          getSession(),
          apiJson<CollectionAssignment[]>('/api/user?view=assignments'),
          apiJson<PointEvent[]>(`/api/submissions?${eventsParams.toString()}`),
        ]);
        const userId = session?.user?.id?.toLowerCase().trim() ?? '';
        if (cancelled) return;
        setAssignments(Array.isArray(assignmentData) ? assignmentData : []);
        const ownEvents = Array.isArray(eventData)
          ? eventData.filter((event) => (typeof event.userId === 'string' ? event.userId.toLowerCase().trim() : '') === userId)
          : [];
        setAgentEvents(ownEvents);
      } catch {
        if (cancelled) return;
        setAssignments([]);
        setAgentEvents([]);
      }
    };

    void loadAgentData();
    return () => {
      cancelled = true;
    };
  }, [isAuthenticated, isAdmin, language, userRole]);

  useEffect(() => {
    return () => {
      if (contributePressTimer.current) {
        window.clearTimeout(contributePressTimer.current);
      }
    };
  }, []);

  const filteredPoints = useMemo(() => points.filter((point) => point.type === activeCategory), [activeCategory, points]);

  const mapPointGroups = useMemo<MapPointGroup[]>(() => {
    const groups = new Map<string, MapPointGroup>();
    for (const point of filteredPoints) {
      if (!point.coordinates) continue;
      if (mapScope === 'bonamoussadi' && !isWithinBonamoussadi(point.coordinates)) continue;
      const latitude = Number(point.coordinates.latitude.toFixed(5));
      const longitude = Number(point.coordinates.longitude.toFixed(5));
      const key = `${latitude}_${longitude}`;
      const existing = groups.get(key);
      if (existing) {
        existing.points.push(point);
      } else {
        groups.set(key, { key, latitude, longitude, points: [point] });
      }
    }
    return Array.from(groups.values());
  }, [filteredPoints, mapScope]);

  const categoryLabel = (type: Category) => {
    const verticalId = LEGACY_CATEGORY_MAP[type] ?? type;
    return getCategoryLabel(verticalId, language);
  };

  const showAgentWidgets = isAuthenticated && userRole !== 'client';
  const activeAssignment = useMemo(() => {
    const active = assignments
      .filter((assignment) => assignment.status === 'in_progress' || assignment.status === 'pending')
      .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());
    return active[0] ?? null;
  }, [assignments]);

  const todayKey = (() => {
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
  })();
  const localDateKey = (iso: string) => {
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return '';
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, '0');
    const d = String(date.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
  };
  const submissionsToday = agentEvents.filter((event) => localDateKey(event.createdAt) === todayKey).length;
  const enrichmentsToday = agentEvents.filter((event) => event.eventType === 'ENRICH_EVENT' && localDateKey(event.createdAt) === todayKey).length;
  const averageQuality = (() => {
    const todayEvents = agentEvents.filter((event) => event.createdAt.slice(0, 10) === todayKey);
    if (todayEvents.length === 0) return 0;
    const total = todayEvents.reduce((sum, event) => {
      const details = (event.details ?? {}) as Record<string, unknown>;
      const score = typeof details.confidenceScore === 'number' ? details.confidenceScore : 75;
      return sum + score;
    }, 0);
    return Math.round(total / todayEvents.length);
  })();
  const streakDays = (() => {
    if (agentEvents.length === 0) return 0;
    const dates = Array.from(new Set(agentEvents.map((event) => event.createdAt.slice(0, 10)))).sort().reverse();
    let streak = 0;
    let cursor = new Date();
    while (true) {
      const key = cursor.toISOString().slice(0, 10);
      if (!dates.includes(key)) break;
      streak += 1;
      cursor.setDate(cursor.getDate() - 1);
    }
    return streak;
  })();
  const streakActiveDays = (() => {
    const dateSet = new Set(agentEvents.map((event) => event.createdAt.slice(0, 10)));
    return Array.from({ length: 7 }, (_, index) => {
      const date = new Date();
      date.setDate(date.getDate() - (6 - index));
      return dateSet.has(date.toISOString().slice(0, 10));
    });
  })();
  const dailyTarget = activeAssignment?.pointsExpected && activeAssignment.pointsExpected > 0 ? activeAssignment.pointsExpected : 10;

  const launchSingleCapture = () => {
    if (isAuthenticated && onContribute) {
      onContribute({ assignment: activeAssignment });
      return;
    }
    onAuth();
  };

  const handleContributePressStart = () => {
    if (!isAuthenticated || !onContribute) return;
    longPressTriggered.current = false;
    if (contributePressTimer.current) {
      window.clearTimeout(contributePressTimer.current);
    }
    contributePressTimer.current = window.setTimeout(() => {
      longPressTriggered.current = true;
      onContribute({ batch: true, assignment: activeAssignment });
    }, 550);
  };

  const handleContributePressEnd = () => {
    if (contributePressTimer.current) {
      window.clearTimeout(contributePressTimer.current);
      contributePressTimer.current = null;
    }
    if (longPressTriggered.current) {
      window.setTimeout(() => {
        longPressTriggered.current = false;
      }, 0);
      return;
    }
    launchSingleCapture();
  };

  return (
    <div
      className="flex h-full min-h-0 flex-col overflow-y-auto bg-[#f9fafb] no-scrollbar"
      style={{ WebkitOverflowScrolling: 'touch' }}
    >
      <header className="px-4 pt-4 pb-3 bg-white border-b border-gray-100 shrink-0">
        <div className="flex items-center justify-between mb-4">
          <div className="flex flex-col">
            <div className="flex items-center space-x-2">
              <BrandLogo size={18} className="shrink-0" />
              <h2 className="text-lg font-bold text-[#1f2933] leading-tight">{t('African Data Layer', 'African Data Layer')}</h2>
              {isAdmin && (
                <span className="px-2 py-0.5 rounded-full bg-[#e7eef4] text-[#0f2b46] text-[9px] font-bold uppercase tracking-widest">
                  {t('Admin', 'Admin')}
                </span>
              )}
              {userRole === 'client' && (
                <span className="px-2 py-0.5 rounded-full bg-[#fff8f4] text-[#c86b4a] text-[9px] font-bold uppercase tracking-widest">
                  {t('Client', 'Client')}
                </span>
              )}
            </div>
            <span className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">
              {mapLockLabel} • {selectedCityLabel}
            </span>
          </div>
          <button
            onClick={isAuthenticated ? onProfile : onAuth}
            className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-400 border border-gray-100"
            aria-label={isAuthenticated ? t('Profile', 'Profil') : t('Sign in', 'Connexion')}
          >
            <User size={18} />
          </button>
        </div>

        <div className="flex items-center space-x-2 text-[10px] font-bold uppercase tracking-widest text-[#4c7c59] mb-3">
          <ShieldCheck size={12} />
          <span>{t('Offline-first sync ready', 'Synchronisation hors ligne prete')}</span>
        </div>
        {isLowEndDevice && (
          <div className="mb-3 rounded-xl border border-[#d5e1eb] bg-[#f2f6fa] px-3 py-2 text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
            {t('Lite Mode Active (Low-end device)', 'Mode Lite actif (appareil entree de gamme)')}
          </div>
        )}

        <div className="relative mb-2">
          <button
            onClick={() => setIsVerticalPickerOpen((prev) => !prev)}
            className="w-full h-11 px-3 bg-gray-100 rounded-xl text-xs font-semibold text-[#0f2b46] flex items-center justify-between"
          >
            <span>
              {t('Vertical', 'Verticale')}: {categoryLabel(activeCategory)}
            </span>
            <ChevronDown size={14} className={`transition-transform ${isVerticalPickerOpen ? 'rotate-180' : ''}`} />
          </button>
          {isVerticalPickerOpen && (
            <div className="absolute left-0 right-0 mt-2 bg-white border border-gray-100 rounded-xl shadow-lg p-2 z-30">
              <div className="grid grid-cols-2 gap-2">
                {selectableCategories.map((category) => {
                  const verticalId = LEGACY_CATEGORY_MAP[category] ?? category;
                  const vertical = VERTICALS[verticalId];
                  const isActive = activeCategory === category;
                  return (
                    <button
                      key={category}
                      type="button"
                      onClick={() => {
                        setActiveCategory(category);
                        setIsVerticalPickerOpen(false);
                      }}
                      className={`h-10 rounded-xl border text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-1 ${
                        isActive ? 'bg-[#0f2b46] text-white border-[#0f2b46]' : 'bg-gray-50 text-gray-600 border-gray-100'
                      }`}
                    >
                      <VerticalIcon name={vertical?.icon ?? 'pill'} size={12} />
                      {categoryLabel(category)}
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        {showAgentWidgets && activeAssignment && (
          <div className="mb-3 rounded-[24px] border border-gray-100 bg-white p-4 shadow-sm space-y-3">
            <div className="flex items-start justify-between gap-3">
              <div>
                <div className="text-[10px] font-bold uppercase tracking-[0.25em] text-gray-400">
                  {t('Active Assignment', 'Affectation active')}
                </div>
                <h4 className="mt-1 text-base font-bold text-gray-900">{activeAssignment.zoneLabel}</h4>
                <p className="mt-1 text-xs text-gray-500">
                  {activeAssignment.assignedVerticals.map((vertical) => getCategoryLabel(vertical, language)).join(', ')}
                </p>
              </div>
              <div className="rounded-full bg-[#f2f6fa] px-3 py-1 text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
                {activeAssignment.status}
              </div>
            </div>
            <div>
              <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-widest text-gray-400">
                <span>{t('Progress', 'Progression')}</span>
                <span>{activeAssignment.pointsSubmitted}/{activeAssignment.pointsExpected}</span>
              </div>
              <div className="mt-2 h-2 rounded-full bg-gray-100 overflow-hidden">
                <div className="h-full rounded-full bg-gradient-to-r from-[#0f2b46] to-[#4c7c59]" style={{ width: `${Math.min(100, activeAssignment.completionRate)}%` }} />
              </div>
            </div>
            <div className="flex items-center justify-between gap-3">
              <div className="text-xs text-gray-500">
                {t('Due', 'Echeance')}: {activeAssignment.dueDate}
              </div>
              {onContribute && (
                <button
                  type="button"
                  onClick={() => onContribute({ assignment: activeAssignment })}
                  className="h-10 rounded-2xl bg-[#0f2b46] px-4 text-[10px] font-bold uppercase tracking-widest text-white"
                >
                  {t('Start Capture', 'Commencer la capture')}
                </button>
              )}
            </div>
          </div>
        )}

        {showAgentWidgets && (
          <div className="mb-3 grid grid-cols-1 gap-3">
            <DailyProgressWidget
              language={language}
              submissionsToday={submissionsToday}
              enrichmentsToday={enrichmentsToday}
              averageQuality={averageQuality}
              streakDays={streakDays}
              dailyTarget={dailyTarget}
            />
            <StreakTracker language={language} streakDays={streakDays} activeDays={streakActiveDays} />
          </div>
        )}
      </header>

      <div className="relative flex flex-1 flex-col overflow-hidden min-h-[26rem]">
        {viewMode === 'map' && (
          <Suspense
            fallback={
              <div className="flex-1 bg-[#e7eef4] relative overflow-hidden z-0 min-h-0 p-4">
                <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
                  {t('Loading map...', 'Chargement de la carte...')}
                </div>
              </div>
            }
          >
            <HomeMap
              mapScope={mapScope}
              mapCenter={mapCenter}
              mapZoom={mapZoom}
              mapMinZoom={mapMinZoom}
              mapBounds={mapBounds}
              mapPointGroups={mapPointGroups}
              selectedCityLabel={selectedCityLabel}
              onSelectPoint={onSelectPoint}
              categoryLabel={categoryLabel}
              formatExplorerPrimaryMeta={formatExplorerPrimaryMeta}
              formatPharmacyOpenStatus={formatPharmacyOpenStatus}
              language={language}
              t={t}
              isLowEndDevice={isLowEndDevice}
            />
          </Suspense>
        )}
        {viewMode === 'list' && (
          <div className="flex-1 relative z-30 bg-[#f9fafb] overflow-y-auto no-scrollbar min-h-0" style={{ WebkitOverflowScrolling: 'touch' }}>
            <div className="p-4 space-y-3 pb-24">
              {isLoadingPoints && (
                <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
                  {t('Loading data points...', 'Chargement des points de donnees...')}
                </div>
              )}
              {filteredPoints.map((point) => (
                <button
                  key={point.id}
                  onClick={() => onSelectPoint(point)}
                  className="w-full text-left bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex items-center space-x-4 active:scale-[0.98] transition-transform"
                >
                  {(() => { const vid = LEGACY_CATEGORY_MAP[point.type] ?? point.type; const v = VERTICALS[vid]; return (
                    <div className="p-3 rounded-xl" style={{ backgroundColor: v?.bgColor ?? '#f3f4f6', color: v?.color ?? '#374151' }}>
                      <VerticalIcon name={v?.icon ?? 'pill'} size={20} />
                    </div>
                  ); })()}
                  <div className="flex-1">
                    <div className="flex justify-between items-start">
                      <h4 className="font-semibold text-gray-900 text-sm">{point.name}</h4>
                      {typeof point.price === 'number' && <span className="font-bold text-gray-900 text-sm">{point.price} {point.currency}</span>}
                    </div>
                    <p className="text-xs text-gray-500 truncate mt-1">{formatExplorerPrimaryMeta(point)}</p>
                    {point.type === Category.PHARMACY && (
                      <p className="text-[10px] text-gray-500 mt-1 uppercase tracking-wider">{formatPharmacyOpenStatus(point)}</p>
                    )}
                    <div className="flex items-center space-x-2 mt-2">
                      <span className="text-[10px] font-medium text-gray-400 uppercase">{t('Updated', 'Mis a jour')} {point.lastUpdated}</span>
                      {point.verified && (
                        <span className="text-[8px] px-1.5 py-0.5 bg-[#eaf3ee] text-[#4c7c59] rounded-full font-bold uppercase tracking-wider">{t('Verified', 'Verifie')}</span>
                      )}
                    </div>
                  </div>
                  <MapPin size={16} className="text-gray-300" />
                </button>
              ))}
            </div>
          </div>
        )}

        <button
          onClick={() => setViewMode((v) => (v === 'map' ? 'list' : 'map'))}
          className="fixed bottom-[calc(6rem+var(--safe-bottom))] left-1/2 -translate-x-1/2 px-5 py-2.5 bg-[#1f2933] text-white rounded-full shadow-2xl flex items-center space-x-2 z-40 hover:bg-black active:scale-95 transition-all"
        >
          {viewMode === 'map' ? <List size={16} /> : <MapIcon size={16} />}
          <span className="text-xs font-bold uppercase tracking-wider">{viewMode === 'map' ? t('List View', 'Vue liste') : t('Map View', 'Vue carte')}</span>
        </button>

        {onContribute && (
          <button
            type="button"
            onClick={(event) => event.preventDefault()}
            onKeyDown={(event) => {
              if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault();
                launchSingleCapture();
              }
            }}
            onPointerDown={handleContributePressStart}
            onPointerUp={handleContributePressEnd}
            onPointerLeave={() => {
              if (contributePressTimer.current) {
                window.clearTimeout(contributePressTimer.current);
                contributePressTimer.current = null;
              }
            }}
            onPointerCancel={() => {
              if (contributePressTimer.current) {
                window.clearTimeout(contributePressTimer.current);
                contributePressTimer.current = null;
              }
            }}
            onContextMenu={(event) => event.preventDefault()}
            className="fixed bottom-[calc(6rem+var(--safe-bottom))] right-4 w-14 h-14 bg-[#c86b4a] text-white rounded-full shadow-2xl flex items-center justify-center z-40 hover:bg-[#b85f3f] active:scale-95 transition-all"
            aria-label={
              isAuthenticated
                ? t('Contribute', 'Contribuer')
                : t('Sign in to contribute', 'Connectez-vous pour contribuer')
            }
          >
            <Plus size={22} />
          </button>
        )}

        {!isAuthenticated && (
          <div className="absolute top-20 left-4 right-4 bg-white/95 backdrop-blur p-3 rounded-xl shadow-xl border border-[#f2f4f7] z-20 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold text-[#c86b4a] uppercase tracking-widest">{t('Contributor Access', 'Acces contributeur')}</span>
              <p className="text-xs text-gray-700 font-medium">{t('Log in to add data and earn XP.', 'Connectez-vous pour ajouter des donnees et gagner des XP.')}</p>
            </div>
            <button
              onClick={onAuth}
              className="px-4 py-2 bg-[#0f2b46] text-white text-[10px] font-bold uppercase rounded-xl tracking-wide hover:bg-[#0b2236]"
            >
              {t('Sign In', 'Connexion')}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;

import React, { useEffect, useState } from 'react';
import {
  AlertTriangle,
  ArrowLeft,
  Award,
  BadgeCheck,
  Calendar,
  Gift,
  MapPin,
  Settings as SettingsIcon,
  Trash2,
  Wallet
} from 'lucide-react';
import { apiJson } from '../../lib/client/api';
import { clearSyncErrorRecords, listSyncErrorRecords, type SyncErrorRecord } from '../../lib/client/offlineQueue';
import type { CollectionAssignment, MapScope, PointEvent, UserProfile } from '../../shared/types';
import { categoryLabel as getCategoryLabelFromRegistry } from '../../shared/verticals';

interface Props {
  onBack: () => void;
  onSettings: () => void;
  onRedeem: () => void;
  onSubmissionQueue: () => void;
  language: 'en' | 'fr';
}

const Profile: React.FC<Props> = ({ onBack, onSettings, onRedeem, onSubmissionQueue, language }) => {
  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
  const historyPreviewLimit = 5;
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [loadError, setLoadError] = useState('');
  const [userLocation, setUserLocation] = useState(t('Location not set', 'Position non definie'));
  const [history, setHistory] = useState<Array<{ id: string; date: string; location: string; type: string; xp: number }>>([]);
  const [showAllHistory, setShowAllHistory] = useState(false);
  const [syncErrors, setSyncErrors] = useState<SyncErrorRecord[]>([]);
  const [isLoadingSyncErrors, setIsLoadingSyncErrors] = useState(true);
  const [isClearingSyncErrors, setIsClearingSyncErrors] = useState(false);
  const [syncErrorActionError, setSyncErrorActionError] = useState('');
  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
  const [isLoadingAssignments, setIsLoadingAssignments] = useState(true);
  const [assignmentError, setAssignmentError] = useState('');
  const [isUpdatingAssignmentId, setIsUpdatingAssignmentId] = useState<string | null>(null);
  const normalizeMapScope = (value: unknown, isAdminMode: boolean): MapScope => {
    if (isAdminMode) return 'global';
    if (value === 'cameroon' || value === 'global') return value;
    return 'bonamoussadi';
  };
  const activeMapScope = normalizeMapScope(profile?.mapScope, Boolean(profile?.isAdmin));
  const isMapUnlocked = activeMapScope !== 'bonamoussadi';

  const formatHistoryDate = (iso: string) => {
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return t('Unknown', 'Inconnu');

    const now = new Date();
    const sameDay = now.toDateString() === date.toDateString();
    const yesterday = new Date(now);
    yesterday.setDate(now.getDate() - 1);
    const isYesterday = yesterday.toDateString() === date.toDateString();
    const time = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    if (sameDay) return language === 'fr' ? `Aujourd'hui • ${time}` : `Today • ${time}`;
    if (isYesterday) return language === 'fr' ? `Hier • ${time}` : `Yesterday • ${time}`;
    return `${date.toLocaleDateString([], { month: 'short', day: '2-digit' })} • ${time}`;
  };

  const submissionToHistory = (submission: PointEvent) => {
    const details = (submission.details ?? {}) as Record<string, unknown>;
    const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
    const locationLabel = siteName || `GPS: ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
    const typeLabel = getCategoryLabelFromRegistry(submission.category, language);
    const rawXp = details.xpAwarded;
    const xpAwarded = typeof rawXp === 'number' && Number.isFinite(rawXp) ? rawXp : 5;

    return {
      id: submission.id,
      date: formatHistoryDate(submission.createdAt),
      location: locationLabel,
      type: typeLabel,
      xp: xpAwarded
    };
  };

  const categoryLabel = (category: SyncErrorRecord['payloadSummary']['category']) => {
    return getCategoryLabelFromRegistry(category, language);
  };

  useEffect(() => {
    const loadProfile = async () => {
      try {
        setIsLoading(true);
        setLoadError('');
        const data = await apiJson<UserProfile>('/api/user');
        setProfile(data);
        setShowAllHistory(false);

        try {
          const userId = typeof data?.id === 'string' ? data.id.toLowerCase().trim() : '';
          const scope = normalizeMapScope(data?.mapScope, Boolean(data?.isAdmin));
          const params = new URLSearchParams({ view: 'events' });
          if (scope !== 'bonamoussadi') params.set('scope', scope);
          const submissions = await apiJson<PointEvent[]>(`/api/submissions?${params.toString()}`);
          if (!userId) {
            setHistory([]);
            setUserLocation(t('Location not set', 'Position non definie'));
            return;
          }

          const ownSubmissions = (Array.isArray(submissions) ? submissions : [])
            .filter((submission) => (typeof submission.userId === 'string' ? submission.userId.toLowerCase().trim() : '') === userId)
            .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

          setHistory(ownSubmissions.map(submissionToHistory));

          const latest = ownSubmissions[0];
          if (latest) {
            const details = (latest.details ?? {}) as Record<string, unknown>;
            const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
            setUserLocation(siteName || `GPS ${latest.location.latitude.toFixed(4)}°, ${latest.location.longitude.toFixed(4)}°`);
          } else {
            setUserLocation(t('No contributions yet', 'Pas encore de contributions'));
          }
        } catch {
          setHistory([]);
          setUserLocation(t('Location not set', 'Position non definie'));
        }
      } catch {
        setProfile(null);
        setLoadError(t('Unable to load profile.', 'Impossible de charger le profil.'));
        setHistory([]);
        setUserLocation(t('Location not set', 'Position non definie'));
      } finally {
        setIsLoading(false);
      }
    };
    loadProfile();
  }, [language]);

  const visibleHistory = showAllHistory ? history : history.slice(0, historyPreviewLimit);
  const canToggleHistory = history.length > historyPreviewLimit;

  useEffect(() => {
    let cancelled = false;

    const loadAssignments = async () => {
      try {
        setIsLoadingAssignments(true);
        setAssignmentError('');
        const data = await apiJson<CollectionAssignment[]>('/api/user?view=assignments');
        if (cancelled) return;
        setAssignments(Array.isArray(data) ? data : []);
      } catch (error) {
        if (cancelled) return;
        const message =
          error instanceof Error
            ? error.message
            : t('Unable to load assignments.', 'Impossible de charger les affectations.');
        setAssignmentError(message);
        setAssignments([]);
      } finally {
        if (!cancelled) setIsLoadingAssignments(false);
      }
    };

    void loadAssignments();
    return () => {
      cancelled = true;
    };
  }, [language]);

  useEffect(() => {
    let cancelled = false;

    const loadSyncErrors = async () => {
      try {
        setIsLoadingSyncErrors(true);
        const records = await listSyncErrorRecords();
        if (!cancelled) setSyncErrors(records);
      } catch {
        if (!cancelled) setSyncErrors([]);
      } finally {
        if (!cancelled) setIsLoadingSyncErrors(false);
      }
    };

    void loadSyncErrors();
    return () => {
      cancelled = true;
    };
  }, []);

  const handleClearSyncErrors = async () => {
    if (isClearingSyncErrors) return;
    setSyncErrorActionError('');
    try {
      setIsClearingSyncErrors(true);
      await clearSyncErrorRecords();
      setSyncErrors([]);
    } catch {
      setSyncErrorActionError(t('Unable to clear sync errors.', 'Impossible d\'effacer les erreurs de synchronisation.'));
    } finally {
      setIsClearingSyncErrors(false);
    }
  };

  const handleAssignmentStatus = async (assignmentId: string, status: CollectionAssignment['status']) => {
    if (isUpdatingAssignmentId) return;
    setAssignmentError('');
    try {
      setIsUpdatingAssignmentId(assignmentId);
      const updated = await apiJson<CollectionAssignment>('/api/user?view=assignments', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: assignmentId, status }),
      });
      setAssignments((prev) => prev.map((assignment) => (assignment.id === assignmentId ? updated : assignment)));
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : t('Unable to update assignment.', 'Impossible de mettre a jour l\'affectation.');
      setAssignmentError(message);
    } finally {
      setIsUpdatingAssignmentId(null);
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#f9fafb] overflow-y-auto no-scrollbar">
      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center justify-between">
        <button onClick={onBack} className="p-2 -ml-2 text-gray-700 hover:text-[#0f2b46] transition-colors">
          <ArrowLeft size={20} />
        </button>
        <h3 className="text-sm font-bold mx-auto">{t('Dashboard', 'Tableau de bord')}</h3>
        <button onClick={onSettings} className="p-2 text-[#0f2b46] absolute right-2">
          <SettingsIcon size={20} />
        </button>
      </div>

      <div className="p-4 space-y-6">
        <div className="flex flex-col items-center py-4 text-center">
          <div className="relative mb-4">
            <div className="w-24 h-24 rounded-full border-4 border-white shadow-xl bg-[#e7eef4] overflow-hidden">
              <img src="https://picsum.photos/seed/jeanpaul/300/300" alt={t('avatar', 'avatar')} className="w-full h-full object-cover" />
            </div>
            <div className="absolute -bottom-1 -right-1 p-1 bg-[#4c7c59] rounded-full border-2 border-white">
              <BadgeCheck size={14} className="text-white" />
            </div>
          </div>
          <h2 className="text-xl font-bold text-gray-900">
            {isLoading ? (
              <span className="inline-block h-4 w-40 rounded-full bg-gray-200 animate-pulse"></span>
            ) : (
              profile?.name || profile?.phone || profile?.email || t('Contributor', 'Contributeur')
            )}
          </h2>
          {!isLoading && (
            <div className="flex items-center justify-center text-[10px] text-gray-400 mt-1 font-bold uppercase tracking-widest space-x-2">
              <MapPin size={12} />
              <span>{userLocation}</span>
            </div>
          )}
          {loadError && (
            <div className="mt-2 text-[10px] font-bold uppercase tracking-widest text-red-500">
              {loadError}
            </div>
          )}
          <div className="mt-4">
            <span className="px-4 py-1.5 bg-[#e7eef4] text-[#0f2b46] text-[10px] font-bold rounded-full uppercase tracking-widest border border-[#d5e1eb] shadow-sm">
              {t('Senior Contributor', 'Contributeur senior')}
            </span>
          </div>
        </div>

        <button
          type="button"
          onClick={onSubmissionQueue}
          className="w-full rounded-2xl border border-[#d5e1eb] bg-white p-4 text-left shadow-sm"
        >
          <div className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
            {t('Submission Queue', 'File de soumission')}
          </div>
          <div className="mt-1 text-sm font-semibold text-gray-900">
            {t('Manage pending sync, failed items, and queued drafts.', 'Gerer la sync en attente, les echecs et les brouillons en file.')}
          </div>
        </button>

        <div className="bg-[#0f2b46] rounded-2xl p-6 text-white shadow-xl flex items-center justify-between relative overflow-hidden">
          <div className="relative z-10 space-y-1">
            <span className="text-[10px] font-bold uppercase tracking-widest opacity-80">{t('XP Balance', 'Solde XP')}</span>
            <div className="flex items-baseline space-x-1">
              {isLoading ? (
                <div className="h-8 w-24 rounded-lg bg-white/20 animate-pulse"></div>
              ) : (
                <>
                  <h3 className="text-3xl font-extrabold tracking-tight">{profile?.XP?.toLocaleString?.() ?? '0'}</h3>
                  <span className="text-lg font-bold opacity-60">XP</span>
                </>
              )}
            </div>
          </div>
          <div className="relative z-10">
            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-sm border border-white/30">
              <Award size={24} />
            </div>
          </div>
        </div>

        {profile?.isAdmin && (
          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">
                  {t('Admin Map Access', 'Acces carte admin')}
                </span>
                <span className="text-sm font-bold text-gray-900">
                  {t('Unlock worldwide map', 'Debloquer la carte mondiale')}
                </span>
              </div>
              <span className="inline-flex items-center rounded-full bg-[#eaf3ee] px-3 py-1 text-[10px] font-bold uppercase tracking-widest text-[#4c7c59]">
                {t('Enabled', 'Active')}
              </span>
            </div>
            <p className="text-xs text-gray-500">
              {isMapUnlocked
                ? t('Explorer map is unlocked worldwide.', 'La carte Explorer est debloquee dans le monde entier.')
                : t('Explorer map is locked to Bonamoussadi.', 'La carte Explorer est limitee a Bonamoussadi.')}
            </p>
          </div>
        )}

        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
          <div className="flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">
                {t('Collection Workflow', 'Workflow de collecte')}
              </span>
              <span className="text-sm font-bold text-gray-900">
                {t('My Weekly Assignments', 'Mes affectations hebdomadaires')}
              </span>
            </div>
            <span className="inline-flex items-center rounded-full bg-[#e7eef4] px-3 py-1 text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
              {assignments.length}
            </span>
          </div>

          {assignmentError && (
            <div className="rounded-xl border border-red-100 bg-red-50 p-3 text-[11px] text-red-600">
              {assignmentError}
            </div>
          )}

          {isLoadingAssignments ? (
            <div className="text-xs text-gray-500">{t('Loading assignments...', 'Chargement des affectations...')}</div>
          ) : assignments.length === 0 ? (
            <div className="text-xs text-gray-500">
              {t('No active assignments yet.', 'Aucune affectation active pour le moment.')}
            </div>
          ) : (
            <div className="space-y-2">
              {assignments.map((assignment) => {
                const canStart = assignment.status === 'pending';
                const canComplete = assignment.status === 'in_progress';
                const isUpdating = isUpdatingAssignmentId === assignment.id;
                const statusLabel =
                  assignment.status === 'pending'
                    ? t('Pending', 'En attente')
                    : assignment.status === 'in_progress'
                      ? t('In progress', 'En cours')
                      : assignment.status === 'completed'
                        ? t('Completed', 'Termine')
                        : t('Expired', 'Expire');
                return (
                  <div key={assignment.id} className="rounded-xl border border-gray-100 p-3 bg-[#f9fafb] space-y-2">
                    <div className="flex items-center justify-between">
                      <div className="text-xs font-bold text-gray-900">{assignment.zoneLabel}</div>
                      <span className="text-[10px] font-bold uppercase tracking-widest text-gray-500">{statusLabel}</span>
                    </div>
                    <div className="text-[11px] text-gray-600">
                      {t('Due', 'Echeance')}: {assignment.dueDate}
                    </div>
                    <div className="text-[11px] text-gray-600">
                      {assignment.pointsSubmitted}/{assignment.pointsExpected} {t('points', 'points')} · {assignment.completionRate}%
                    </div>
                    <div className="text-[10px] text-gray-500">
                      {assignment.assignedVerticals
                        .map((vertical) => getCategoryLabelFromRegistry(vertical, language))
                        .join(', ')}
                    </div>
                    {(canStart || canComplete) && (
                      <button
                        type="button"
                        disabled={isUpdating}
                        onClick={() => handleAssignmentStatus(assignment.id, canStart ? 'in_progress' : 'completed')}
                        className={`h-9 rounded-xl px-3 text-[10px] font-bold uppercase tracking-widest ${
                          isUpdating ? 'bg-gray-100 text-gray-400' : 'bg-[#0f2b46] text-white'
                        }`}
                      >
                        {isUpdating
                          ? t('Updating...', 'Mise a jour...')
                          : canStart
                            ? t('Start Assignment', 'Demarrer affectation')
                            : t('Mark Completed', 'Marquer termine')}
                      </button>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>

        <div className="grid grid-cols-2 gap-4">
          <button
            onClick={onRedeem}
            className="h-14 bg-white text-[#0f2b46] border border-[#d5e1eb] rounded-xl text-[10px] font-bold uppercase tracking-widest shadow-sm hover:bg-[#f2f4f7] transition-all flex items-center justify-center space-x-2"
          >
            <Gift size={16} />
            <span>{t('Redeem XP', 'Echanger XP')}</span>
          </button>
          <button className="h-14 bg-[#c86b4a] text-white rounded-xl text-[10px] font-bold uppercase tracking-widest shadow-lg hover:bg-[#b85f3f] transition-all flex items-center justify-center space-x-2">
            <Wallet size={16} />
            <span>{t('Convert to Rewards', 'Convertir en recompenses')}</span>
          </button>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
            <div className="flex items-center space-x-2 text-[#4c7c59]">
              <BadgeCheck size={16} />
              <span className="text-[10px] font-bold uppercase tracking-widest">{t('Trust Score', 'Score de confiance')}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-2xl font-bold text-gray-900">98%</span>
              <div className="mt-2 h-1 w-full bg-gray-50 rounded-full overflow-hidden">
                <div className="h-full bg-[#4c7c59] rounded-full transition-all duration-1000" style={{ width: '98%' }} />
              </div>
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
            <div className="flex items-center space-x-2 text-[#0f2b46]">
              <Calendar size={16} />
              <span className="text-[10px] font-bold uppercase tracking-widest">{t('Badges', 'Badges')}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-2xl font-bold text-gray-900">7</span>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{t('Next: Urban Validator', 'Suivant : Validateur urbain')}</p>
            </div>
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between px-1">
            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Contribution History', 'Historique des contributions')}</h4>
            {canToggleHistory && (
              <button
                type="button"
                onClick={() => setShowAllHistory((prev) => !prev)}
                className="text-[10px] font-bold text-[#0f2b46] uppercase"
              >
                {showAllHistory ? t('Show Less', 'Voir moins') : t('View All', 'Voir tout')}
              </button>
            )}
          </div>

          <div className="space-y-3">
            {history.length === 0 && (
              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
                {t('No contributions yet. Add your first report to build your history.', 'Aucune contribution pour le moment. Ajoutez votre premier signalement pour construire votre historique.')}
              </div>
            )}
            {visibleHistory.map((act) => (
              <div key={act.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center text-gray-400">
                    <Calendar size={18} />
                  </div>
                  <div className="flex flex-col">
                    <span className="text-xs font-bold text-gray-900">{act.type}</span>
                    <span className="text-[10px] text-gray-400 font-bold uppercase">{act.date}</span>
                    <span className="text-[10px] text-gray-400 font-medium">{act.location}</span>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-xs font-bold text-[#4c7c59]">+{act.xp} XP</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between px-1">
            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Sync Errors', 'Erreurs de synchronisation')}</h4>
            {syncErrors.length > 0 && (
              <button
                type="button"
                onClick={handleClearSyncErrors}
                disabled={isClearingSyncErrors}
                className={`text-[10px] font-bold uppercase flex items-center space-x-1 ${isClearingSyncErrors ? 'text-gray-300' : 'text-[#c86b4a]'}`}
              >
                <Trash2 size={12} />
                <span>{isClearingSyncErrors ? t('Clearing...', 'Suppression...') : t('Clear', 'Effacer')}</span>
              </button>
            )}
          </div>

          {syncErrorActionError && (
            <div className="bg-red-50 border border-red-100 rounded-2xl p-4 text-xs text-red-600">
              {syncErrorActionError}
            </div>
          )}

          {isLoadingSyncErrors && (
            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
              {t('Loading sync errors...', 'Chargement des erreurs de synchronisation...')}
            </div>
          )}

          {!isLoadingSyncErrors && syncErrors.length === 0 && (
            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
              {t('No sync errors on this device.', 'Aucune erreur de synchronisation sur cet appareil.')}
            </div>
          )}

          {!isLoadingSyncErrors && syncErrors.length > 0 && (
            <div className="space-y-3">
              {syncErrors.map((record) => (
                <div key={record.id} className="bg-white p-4 rounded-2xl border border-red-100 shadow-sm space-y-2">
                  <div className="flex items-start space-x-2 text-red-600">
                    <AlertTriangle size={14} className="mt-[1px]" />
                    <span className="text-xs font-semibold">{record.message}</span>
                  </div>
                  <div className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">
                    {formatHistoryDate(record.createdAt)} • {categoryLabel(record.payloadSummary.category)}
                  </div>
                  <div className="text-[11px] text-gray-500">
                    {record.payloadSummary.location
                      ? `GPS: ${record.payloadSummary.location.latitude.toFixed(4)}°, ${record.payloadSummary.location.longitude.toFixed(4)}°`
                      : t('GPS unavailable', 'GPS indisponible')}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
        <div className="h-24"></div>
      </div>
    </div>
  );
};

export default Profile;

