 93→    93→  const base64 = dataUrl.slice(commaIndex + 1);
 94→    94→  if (!base64) return null;
 95→    95→  const binary = atob(base64);
 96→    96→  const bytes = new Uint8Array(binary.length);
 97→    97→  for (let i = 0; i < binary.length; i += 1) {
