100→   100→  return bytes;
101→   101→}
102→   102→
103→   103→function bytesToDataUrl(bytes: Uint8Array, mime: string): string {
104→   104→  let binary = '';
105→   105→  for (let i = 0; i < bytes.length; i += 1) {
106→   106→    binary += String.fromCharCode(bytes[i] ?? 0);
107→   107→  }
108→   108→  return `data:${mime};base64,${btoa(binary)}`;
109→   109→}
110→   110→
111→   111→function extractJpegExifSegment(bytes: Uint8Array): Uint8Array | null {
112→   112→  if (bytes.length < 4) return null;
113→   113→  if (bytes[0] !== 0xff || bytes[1] !== 0xd8) return null;
114→   114→
115→   115→  let offset = 2;
116→   116→  while (offset + 4 <= bytes.length) {
117→   117→    if (bytes[offset] !== 0xff) {
118→   118→      offset += 1;
119→   119→      continue;
120→   120→    }
121→   121→
122→   122→    const marker = bytes[offset + 1];
123→   123→    if (marker === 0xd8 || marker === 0x01 || (marker >= 0xd0 && marker <= 0xd7)) {
124→   124→      offset += 2;
125→   125→      continue;
126→   126→    }
127→   127→    if (marker === 0xda || marker === 0xd9) break;
128→   128→
129→   129→    const segmentLength = ((bytes[offset + 2] ?? 0) << 8) | (bytes[offset + 3] ?? 0);
130→   130→    if (segmentLength < 2) break;
131→   131→    const segmentEnd = offset + 2 + segmentLength;
132→   132→    if (segmentEnd > bytes.length) break;
133→   133→
134→   134→    if (marker === 0xe1 && segmentLength >= 8) {
135→   135→      const signature = String.fromCharCode(
136→   136→        bytes[offset + 4] ?? 0,
137→   137→        bytes[offset + 5] ?? 0,
138→   138→        bytes[offset + 6] ?? 0,
139→   139→        bytes[offset + 7] ?? 0,
140→   140→        bytes[offset + 8] ?? 0,
141→   141→        bytes[offset + 9] ?? 0,
142→   142→      );
143→   143→      if (signature === 'Exif\0\0') {
144→   144→        return bytes.slice(offset, segmentEnd);
145→   145→      }
146→   146→    }
147→   147→
148→   148→    offset = segmentEnd;
149→   149→  }
150→   150→
151→   151→  return null;
152→   152→}
153→   153→
154→   154→function injectExifIntoJpeg(compressedBytes: Uint8Array, exifSegment: Uint8Array): Uint8Array | null {
155→   155→  if (compressedBytes.length < 2) return null;
156→   156→  if (compressedBytes[0] !== 0xff || compressedBytes[1] !== 0xd8) return null;
157→   157→  if (!exifSegment.length) return null;
158→   158→
159→   159→  const merged = new Uint8Array(compressedBytes.length + exifSegment.length);
160→   160→  merged[0] = compressedBytes[0];
161→   161→  merged[1] = compressedBytes[1];
162→   162→  merged.set(exifSegment, 2);
163→   163→  merged.set(compressedBytes.slice(2), 2 + exifSegment.length);
164→   164→  return merged;
165→   165→}
