167→   167→async function preserveJpegExif(originalFile: File, compressedDataUrl: string): Promise<string> {
168→   168→  if (!JPEG_MIME_TYPES.has((originalFile.type || '').toLowerCase())) return compressedDataUrl;
169→   169→
170→   170→  const originalBytes = new Uint8Array(await originalFile.arrayBuffer());
171→   171→  const exifSegment = extractJpegExifSegment(originalBytes);
172→   172→  if (!exifSegment) return compressedDataUrl;
173→   173→
174→   174→  const compressedBytes = dataUrlToBytes(compressedDataUrl);
175→   175→  if (!compressedBytes) return compressedDataUrl;
176→   176→  if (extractJpegExifSegment(compressedBytes)) return compressedDataUrl;
177→   177→
178→   178→  const merged = injectExifIntoJpeg(compressedBytes, exifSegment);
179→   179→  if (!merged) return compressedDataUrl;
180→   180→  return bytesToDataUrl(merged, 'image/jpeg');
181→   181→}
