190→   190→  if (ipadMatch) return { make: 'Apple', model: 'iPad' };
191→   191→  // Android device detection
192→   192→  const androidMatch = ua.match(/;\s*([^;)]+)\s+Build\//);
193→   193→  if (androidMatch) return { make: null, model: androidMatch[1]?.trim() ?? null };
194→   194→  return { make: null, model: null };
