 62→
 63→function normalizeText(input: unknown): string | null {
 64→  if (typeof input !== 'string') return null;
 65→  const value = input.trim();
 66→  return value || null;
 67→}
 68→
 69→function normalizeStringList(input: unknown): string[] {
 70→  if (!Array.isArray(input)) return [];
 71→  const cleaned = input
 72→    .map((value) => (typeof value === 'string' ? value.trim() : ''))
 73→    .filter((value) => value.length > 0);
 74→  return Array.from(new Set(cleaned));
 75→}
 76→
 77→function normalizeNumber(input: unknown): number | null {
 78→  if (typeof input === 'number' && Number.isFinite(input)) return input;
 79→  if (typeof input === 'string') {
 80→    const parsed = Number(input.trim());
 81→    if (Number.isFinite(parsed)) return parsed;
 82→  }
 83→  return null;
 84→}
 85→
 86→function optionLabel(option: EnrichFieldOption, language: 'en' | 'fr'): string {
 87→  return language === 'fr' ? option.labelFr : option.labelEn;
 88→}
