  1→import React, { useEffect, useState } from 'react';
  2→import {
  3→  AlertTriangle,
  4→  ArrowLeft,
  5→  Award,
  6→  BadgeCheck,
  7→  Calendar,
  8→  Gift,
  9→  MapPin,
 10→  Settings as SettingsIcon,
 11→  Trash2,
 12→  Wallet
 13→} from 'lucide-react';
 14→import { apiJson } from '../../lib/client/api';
 15→import { clearSyncErrorRecords, listSyncErrorRecords, type SyncErrorRecord } from '../../lib/client/offlineQueue';
 16→import type { CollectionAssignment, MapScope, PointEvent, UserProfile } from '../../shared/types';
 17→import { categoryLabel as getCategoryLabelFromRegistry } from '../../shared/verticals';
 18→
 19→interface Props {
 20→  onBack: () => void;
 21→  onSettings: () => void;
 22→  onRedeem: () => void;
 23→  onSubmissionQueue: () => void;
 24→  language: 'en' | 'fr';
 25→}
 26→
 27→const Profile: React.FC<Props> = ({ onBack, onSettings, onRedeem, onSubmissionQueue, language }) => {
 28→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 29→  const historyPreviewLimit = 5;
 30→  const [profile, setProfile] = useState<UserProfile | null>(null);
 31→  const [isLoading, setIsLoading] = useState(true);
 32→  const [loadError, setLoadError] = useState('');
 33→  const [userLocation, setUserLocation] = useState(t('Location not set', 'Position non definie'));
 34→  const [history, setHistory] = useState<Array<{ id: string; date: string; location: string; type: string; xp: number }>>([]);
 35→  const [computedXP, setComputedXP] = useState<number | null>(null);
 36→  const [showAllHistory, setShowAllHistory] = useState(false);
 37→  const [syncErrors, setSyncErrors] = useState<SyncErrorRecord[]>([]);
 38→  const [isLoadingSyncErrors, setIsLoadingSyncErrors] = useState(true);
 39→  const [isClearingSyncErrors, setIsClearingSyncErrors] = useState(false);
 40→  const [syncErrorActionError, setSyncErrorActionError] = useState('');
 41→  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
 42→  const [isLoadingAssignments, setIsLoadingAssignments] = useState(true);
 43→  const [assignmentError, setAssignmentError] = useState('');
 44→  const [isUpdatingAssignmentId, setIsUpdatingAssignmentId] = useState<string | null>(null);
 45→  const normalizeMapScope = (value: unknown, isAdminMode: boolean): MapScope => {
 46→    if (isAdminMode) return 'global';
 47→    if (value === 'cameroon' || value === 'global') return value;
 48→    return 'bonamoussadi';
 49→  };
 50→  const activeMapScope = normalizeMapScope(profile?.mapScope, Boolean(profile?.isAdmin));
 51→  const isMapUnlocked = activeMapScope !== 'bonamoussadi';
 52→
 53→  const formatHistoryDate = (iso: string) => {
 54→    const date = new Date(iso);
 55→    if (Number.isNaN(date.getTime())) return t('Unknown', 'Inconnu');
 56→
 57→    const now = new Date();
 58→    const sameDay = now.toDateString() === date.toDateString();
 59→    const yesterday = new Date(now);
 60→    yesterday.setDate(now.getDate() - 1);
 61→    const isYesterday = yesterday.toDateString() === date.toDateString();
 62→    const time = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
 63→
 64→    if (sameDay) return language === 'fr' ? `Aujourd'hui • ${time}` : `Today • ${time}`;
 65→    if (isYesterday) return language === 'fr' ? `Hier • ${time}` : `Yesterday • ${time}`;
 66→    return `${date.toLocaleDateString([], { month: 'short', day: '2-digit' })} • ${time}`;
 67→  };
 68→
 69→  const submissionToHistory = (submission: PointEvent) => {
 70→    const details = (submission.details ?? {}) as Record<string, unknown>;
 71→    const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
 72→    const locationLabel = siteName || `GPS: ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
 73→    const typeLabel = getCategoryLabelFromRegistry(submission.category, language);
 74→    const rawXp = details.xpAwarded;
 75→    const xpAwarded = typeof rawXp === 'number' && Number.isFinite(rawXp) ? rawXp : 0;
 76→
 77→    return {
 78→      id: submission.id,
 79→      date: formatHistoryDate(submission.createdAt),
 80→      location: locationLabel,
 81→      type: typeLabel,
 82→      xp: xpAwarded
 83→    };
 84→  };
 85→
 86→  const categoryLabel = (category: SyncErrorRecord['payloadSummary']['category']) => {
 87→    return getCategoryLabelFromRegistry(category, language);
 88→  };
 89→
 90→  useEffect(() => {
 91→    const loadProfile = async () => {
 92→      try {
 93→        setIsLoading(true);
 94→        setLoadError('');
 95→        const data = await apiJson<UserProfile>('/api/user');
 96→        setProfile(data);
 97→        setShowAllHistory(false);
 98→
 99→        try {
100→          const userId = typeof data?.id === 'string' ? data.id.toLowerCase().trim() : '';
101→          const scope = normalizeMapScope(data?.mapScope, Boolean(data?.isAdmin));
102→          const params = new URLSearchParams({ view: 'events' });
103→          if (scope !== 'bonamoussadi') params.set('scope', scope);
104→          const submissions = await apiJson<PointEvent[]>(`/api/submissions?${params.toString()}`);
105→          if (!userId) {
106→            setHistory([]);
107→            setUserLocation(t('Location not set', 'Position non definie'));
108→            return;
109→          }
110→
111→          const ownSubmissions = (Array.isArray(submissions) ? submissions : [])
112→            .filter((submission) => (typeof submission.userId === 'string' ? submission.userId.toLowerCase().trim() : '') === userId)
113→            .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
114→
115→          const historyItems = ownSubmissions.map(submissionToHistory);
116→          setHistory(historyItems);
117→
118→          const totalXP = ownSubmissions.reduce((sum, submission) => {
119→            const details = (submission.details ?? {}) as Record<string, unknown>;
120→            const awarded = typeof details.xpAwarded === 'number' && Number.isFinite(details.xpAwarded) ? details.xpAwarded : 0;
121→            return sum + awarded;
122→          }, 0);
123→          setComputedXP(totalXP);
124→
125→          const latest = ownSubmissions[0];
126→          if (latest) {
127→            const details = (latest.details ?? {}) as Record<string, unknown>;
128→            const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
129→            setUserLocation(siteName || `GPS ${latest.location.latitude.toFixed(4)}°, ${latest.location.longitude.toFixed(4)}°`);
130→          } else {
131→            setUserLocation(t('No contributions yet', 'Pas encore de contributions'));
132→          }
133→        } catch {
134→          setHistory([]);
135→          setUserLocation(t('Location not set', 'Position non definie'));
136→        }
137→      } catch {
138→        setProfile(null);
139→        setLoadError(t('Unable to load profile.', 'Impossible de charger le profil.'));
140→        setHistory([]);
141→        setUserLocation(t('Location not set', 'Position non definie'));
142→      } finally {
143→        setIsLoading(false);
144→      }
145→    };
146→    loadProfile();
147→  }, [language]);
148→
149→  const visibleHistory = showAllHistory ? history : history.slice(0, historyPreviewLimit);
150→  const canToggleHistory = history.length > historyPreviewLimit;
151→
152→  useEffect(() => {
153→    let cancelled = false;
154→
155→    const loadAssignments = async () => {
156→      try {
157→        setIsLoadingAssignments(true);
158→        setAssignmentError('');
159→        const data = await apiJson<CollectionAssignment[]>('/api/user?view=assignments');
160→        if (cancelled) return;
161→        setAssignments(Array.isArray(data) ? data : []);
162→      } catch (error) {
163→        if (cancelled) return;
164→        const message =
165→          error instanceof Error
166→            ? error.message
167→            : t('Unable to load assignments.', 'Impossible de charger les affectations.');
168→        setAssignmentError(message);
169→        setAssignments([]);
170→      } finally {
171→        if (!cancelled) setIsLoadingAssignments(false);
172→      }
173→    };
174→
175→    void loadAssignments();
176→    return () => {
177→      cancelled = true;
178→    };
179→  }, [language]);
180→
181→  useEffect(() => {
182→    let cancelled = false;
183→
184→    const loadSyncErrors = async () => {
185→      try {
186→        setIsLoadingSyncErrors(true);
187→        const records = await listSyncErrorRecords();
188→        if (!cancelled) setSyncErrors(records);
189→      } catch {
190→        if (!cancelled) setSyncErrors([]);
191→      } finally {
192→        if (!cancelled) setIsLoadingSyncErrors(false);
193→      }
194→    };
195→
196→    void loadSyncErrors();
197→    return () => {
198→      cancelled = true;
199→    };
200→  }, []);
201→
202→  const handleClearSyncErrors = async () => {
203→    if (isClearingSyncErrors) return;
204→    setSyncErrorActionError('');
205→    try {
206→      setIsClearingSyncErrors(true);
207→      await clearSyncErrorRecords();
208→      setSyncErrors([]);
209→    } catch {
210→      setSyncErrorActionError(t('Unable to clear sync errors.', 'Impossible d\'effacer les erreurs de synchronisation.'));
211→    } finally {
212→      setIsClearingSyncErrors(false);
213→    }
214→  };
215→
216→  const handleAssignmentStatus = async (assignmentId: string, status: CollectionAssignment['status']) => {
217→    if (isUpdatingAssignmentId) return;
218→    setAssignmentError('');
219→    try {
220→      setIsUpdatingAssignmentId(assignmentId);
221→      const updated = await apiJson<CollectionAssignment>('/api/user?view=assignments', {
222→        method: 'PATCH',
223→        headers: { 'Content-Type': 'application/json' },
224→        body: JSON.stringify({ id: assignmentId, status }),
225→      });
226→      setAssignments((prev) => prev.map((assignment) => (assignment.id === assignmentId ? updated : assignment)));
227→    } catch (error) {
228→      const message =
229→        error instanceof Error
230→          ? error.message
231→          : t('Unable to update assignment.', 'Impossible de mettre a jour l\'affectation.');
232→      setAssignmentError(message);
233→    } finally {
234→      setIsUpdatingAssignmentId(null);
235→    }
236→  };
