  );
};

const MapSizeSync: React.FC<{ active: boolean }> = ({ active }) => {
  const map = useMap();

  useEffect(() => {
    if (!active) return;
    const rafId = requestAnimationFrame(() => {
      map.invalidateSize({ animate: false });
    });
