366→    const m = String(now.getMonth() + 1).padStart(2, '0');
367→    const d = String(now.getDate()).padStart(2, '0');
368→    return `${y}-${m}-${d}`;
369→  })();
370→  const localDateKey = (iso: string) => {
371→    const date = new Date(iso);
372→    if (Number.isNaN(date.getTime())) return '';
373→    const y = date.getFullYear();
374→    const m = String(date.getMonth() + 1).padStart(2, '0');
375→    const d = String(date.getDate()).padStart(2, '0');
376→    return `${y}-${m}-${d}`;
