378→  const submissionsToday = agentEvents.filter((event) => localDateKey(event.createdAt) === todayKey).length;
379→  const enrichmentsToday = agentEvents.filter((event) => event.eventType === 'ENRICH_EVENT' && localDateKey(event.createdAt) === todayKey).length;
380→  const averageQuality = (() => {
381→    const todayEvents = agentEvents.filter((event) => localDateKey(event.createdAt) === todayKey);
382→    if (todayEvents.length === 0) return 0;
383→    const total = todayEvents.reduce((sum, event) => {
384→      const details = (event.details ?? {}) as Record<string, unknown>;
385→      const score = typeof details.confidenceScore === 'number' ? details.confidenceScore : 75;
386→      return sum + score;
387→    }, 0);
388→    return Math.round(total / todayEvents.length);
389→  })();
390→  const streakDays = (() => {
391→    if (agentEvents.length === 0) return 0;
392→    const dates = Array.from(new Set(agentEvents.map((event) => localDateKey(event.createdAt)))).sort().reverse();
393→    let streak = 0;
394→    let cursor = new Date();
395→    while (true) {
396→      const key = localDateKey(cursor.toISOString());
397→      if (!dates.includes(key)) break;
398→      streak += 1;
399→      cursor.setDate(cursor.getDate() - 1);
400→    }
401→    return streak;
402→  })();
403→  const streakActiveDays = (() => {
404→    const dateSet = new Set(agentEvents.map((event) => localDateKey(event.createdAt)));
