 31→function queueTitle(item: QueueItem, language: 'en' | 'fr'): string {
 32→  const details = (item.payload.details ?? {}) as Record<string, unknown>;
 33→  const name =
 34→    (typeof details.siteName === 'string' && details.siteName.trim()) ||
 35→    (typeof details.name === 'string' && details.name.trim()) ||
 36→    (typeof details.roadName === 'string' && details.roadName.trim());
 37→  return name || categoryLabel(item.payload.category, language);
 38→}
