 5→function getDetails(input: Pick<PointEvent, "details"> | SubmissionDetails | null | undefined): SubmissionDetails {
 6→  if (!input) return {};
 7→  if ("details" in input) return (input.details ?? {}) as SubmissionDetails;
 8→  return input;
 9→}
10→
11→function normalizeReviewStatus(details: SubmissionDetails): string {
12→  const value = details.reviewStatus;
13→  return typeof value === "string" ? value.trim().toLowerCase() : "";
14→}
15→
16→function normalizeReviewDecision(details: SubmissionDetails): string {
17→  const value = details.reviewDecision;
18→  return typeof value === "string" ? value.trim().toLowerCase() : "";
19→}
20→
21→function hasRejectedFlag(details: SubmissionDetails): boolean {
22→  const flags = details.reviewFlags;
23→  if (!Array.isArray(flags)) return false;
24→  return flags.some((flag) => typeof flag === "string" && flag.trim().toLowerCase() === "rejected_by_admin");
25→}
26→
27→function normalizeUserId(userId: string): string {
28→  return userId.trim().toLowerCase();
29→}
30→
31→export function isRejectedSubmission(input: Pick<PointEvent, "details"> | SubmissionDetails | null | undefined): boolean {
32→  const details = getDetails(input);
33→  return normalizeReviewDecision(details) === "rejected" || hasRejectedFlag(details);
34→}
35→
36→export function getEffectiveEventXp(input: Pick<PointEvent, "details"> | SubmissionDetails | null | undefined): number {
37→  const details = getDetails(input);
38→  if (isRejectedSubmission(details)) return 0;
39→
40→  const rawXp = details.xpAwarded;
41→  if (typeof rawXp === "number" && Number.isFinite(rawXp)) {
42→    return Math.max(0, Math.round(rawXp));
43→  }
44→
45→  if (normalizeReviewStatus(details) === "pending_review") return 0;
46→  return BASE_EVENT_XP;
47→}
48→
49→export function getUserXpFromEvents(events: readonly PointEvent[], userId: string): number {
50→  const normalizedUserId = normalizeUserId(userId);
51→  return events.reduce((total, event) => {
52→    if (normalizeUserId(event.userId) !== normalizedUserId) return total;
53→    return total + getEffectiveEventXp(event);
54→  }, 0);
55→}
